// Parse SSH Remote request - HTTP -> SSH -> Remote MCP
const body = $input.item.json.body || $input.item.json;

const server = body.server || 'ai-learning';
const tool = body.tool || 'health_check';
const args = body.arguments || {};

// Server paths
const serverPaths = {
  'ai-learning': 'cd /home/dju/mojAiProjekat/New\ folder/mcp-server && python -m ai_learning_mcp',
  'moj-ubuntu': 'cd /home/dju/mcp-servers/moj-ubuntu-server && node index.js',
  'hpe-oneview': 'cd /home/dju/moji\ projekti/MCP_HpOneView && python main.py'
};

const mcpCmd = serverPaths[server] || serverPaths['ai-learning'];

// Build JSON-RPC request
const jsonRpcRequest = JSON.stringify({
  jsonrpc: '2.0',
  id: 1,
  method: 'tools/call',
  params: {
    name: tool,
    arguments: args
  }
});

return [{ json: {
  ssh: {
    host: 'localhost',
    port: 2222,
    username: 'dju',
    password: 'S@alakazu17'
  },
  command: `printf '%s' '${jsonRpcRequest}' | ${mcpCmd}`,
  server,
  tool,
  arguments: args,
  trigger: 'ssh-remote',
  executionId: 'mcp-' + Date.now().toString(36),
  startTime: new Date().toISOString()
} }];

// Prepare health check commands for cron
const healthCommands = [
  { server: 'ai-learning', tool: 'health_check', trigger: 'cron', command: 'cd /home/dju/mojAiProjekat/New folder/mcp-server && printf \'{"jsonrpc":"2.0","id":1,"method":"tools/call","params":{"name":"health_check","arguments":{}}}\' | python -m ai_learning_mcp' },
  { server: 'moj-ubuntu', tool: 'proveri_sistem', trigger: 'cron', command: 'cd /home/dju/mcp-servers/moj-ubuntu-server && printf \'{"jsonrpc":"2.0","id":1,"method":"tools/call","params":{"name":"proveri_sistem","arguments":{}}}\' | node index.js' },
  { server: 'hpe-oneview', tool: 'proveri_servere', trigger: 'cron', command: 'cd /home/dju/moji\ projekti/MCP_HpOneView && printf \'{"jsonrpc":"2.0","id":1,"method":"tools/call","params":{"name":"proveri_servere","arguments":{}}}\' | python main.py' }
];

return healthCommands.map((item, idx) => ({
  json: {
    ...item,
    ssh: {
      host: 'localhost',
      port: 2222,
      username: 'dju',
      password: 'S@alakazu17'
    },
    executionId: 'cron-' + Date.now().toString(36) + '-' + idx,
    startTime: new Date().toISOString()
  }
}));

// Format response as TEXT REPORT
const item = $input.item.json;
const endTime = new Date();
const startTime = new Date(item.startTime || Date.now());
const executionTime = endTime - startTime;

const lines = [];
lines.push('╔══════════════════════════════════════════════════════════════════════╗');
lines.push('║                  MCP COMMAND EXECUTION REPORT                       ║');
lines.push('╚══════════════════════════════════════════════════════════════════════╝');
lines.push('');
lines.push(`  Execution ID : ${item.executionId || 'N/A'}`);
lines.push(`  Timestamp   : ${endTime.toLocaleString()}`);
lines.push(`  Server      : ${item.server || 'local'}`);
lines.push(`  Tool        : ${item.tool || 'custom'}`);
lines.push(`  Status      : ${item.error ? '❌ FAILED' : '✅ SUCCESS'}`);
lines.push(`  Duration    : ${executionTime}ms`);
lines.push('');
lines.push('────────────────────────────────────────────────────────────────────────');
lines.push('                           COMMAND EXECUTED');
lines.push('────────────────────────────────────────────────────────────────────────');
lines.push('');
lines.push('  ' + (item.command || 'N/A'));
lines.push('');
lines.push('────────────────────────────────────────────────────────────────────────');
lines.push('                              OUTPUT');
lines.push('────────────────────────────────────────────────────────────────────────');
lines.push('');

if (item.error) {
  lines.push('  ❌ ERROR:');
  lines.push('  ' + (item.error || 'Unknown error'));
} else {
  const result = item.output || item.response || '';
  if (result) {
    // Add indentation to each line
    const indentedLines = result.split('\n').map(line => '  ' + line);
    lines.push(indentedLines.join('\n'));
  } else {
    lines.push('  (No output)');
  }
}

lines.push('');
lines.push('────────────────────────────────────────────────────────────────────────');
lines.push('                          END OF REPORT');
lines.push('═══════════════════════════════════════════════════════════════════════════');

const report = lines.join('\n');

return [{
  json: {
    success: !item.error,
    executionId: item.executionId,
    server: item.server || 'local',
    tool: item.tool || 'custom',
    command: item.command,
    result: report,
    rawOutput: item.output || item.response || '',
    error: item.error,
    executionTime: executionTime,
    timestamp: endTime.toISOString()
  }
}];
